208	                        FireTimestamp = firedTime
209	                    };
210	
211	                    triggerData.Add(dataHolder);
212	                    triggers.Add(rcvryTrig);
213	                    keys.Add(new TriggerKey(trigName, trigGroup));
214	                }
215	            }
216	        }
217	
218	        // read JobDataMaps with different reader..
219	        for (int i = 0; i < triggers.Count; i++)
220	        {
221	            IOperableTrigger trigger = triggers[i];
222	            TriggerKey key = keys[i];
223	            FiredTriggerRecord dataHolder = triggerData[i];
224	
225	            // load job data map and transfer information
226	            JobDataMap jd = await SelectTriggerJobDataMap(conn, key, cancellationToken).ConfigureAwait(false);
227	            jd.Put(SchedulerConstants.FailedJobOriginalTriggerName, key.Name);
228	            jd.Put(SchedulerConstants.FailedJobOriginalTriggerGroup, key.Group);
229	            jd.Put(SchedulerConstants.FailedJobOriginalTriggerFiretime, Convert.ToString(dataHolder.FireTimestamp, CultureInfo.InvariantCulture)!);
230	            jd.Put(SchedulerConstants.FailedJobOriginalTriggerScheduledFiretime, Convert.ToString(dataHolder.ScheduleTimestamp, CultureInfo.InvariantCulture)!);
231	            trigger.JobDataMap = jd;
232	        }
233	
234	        return triggers;
235	    }
