378	        IOperableTrigger trigger,
379	        string state,
380	        IJobDetail jobDetail,
381	        CancellationToken cancellationToken = default)
382	    {
383	        var existingType = await SelectTriggerType(conn, trigger.Key, cancellationToken).ConfigureAwait(false);
384	
385	        // No need to continue if the trigger type is not found - there's nothing to update.
386	        if (existingType is null) return 0;
387	
388	        // save some clock cycles by unnecessarily writing job data blob ...
389	        var updateJobData = trigger.JobDataMap.Dirty;
390	        var jobData = updateJobData ? SerializeJobData(trigger.JobDataMap) : null;
391	
392	        var sqlUpdate = updateJobData ? SqlUpdateTrigger : SqlUpdateTriggerSkipData;
393	        using var cmd = PrepareCommand(conn, ReplaceTablePrefix(sqlUpdate));
394	
395	        AddCommandParameter(cmd, "schedulerName", schedName);
396	        AddCommandParameter(cmd, "triggerJobName", trigger.JobKey.Name);
397	        AddCommandParameter(cmd, "triggerJobGroup", trigger.JobKey.Group);
398	        AddCommandParameter(cmd, "triggerDescription", trigger.Description);
399	        AddCommandParameter(cmd, "triggerNextFireTime", GetDbDateTimeValue(trigger.GetNextFireTimeUtc()));
400	        AddCommandParameter(cmd, "triggerPreviousFireTime", GetDbDateTimeValue(trigger.GetPreviousFireTimeUtc()));
401	
402	        AddCommandParameter(cmd, "triggerState", state);
403	
404	        var tDel = FindTriggerPersistenceDelegate(trigger);
405	
406	        string type = TriggerTypeBlob;
407	        if (tDel is not null)
408	        {
409	            type = tDel.GetHandledTriggerTypeDiscriminator();
410	        }
411	
412	        AddCommandParameter(cmd, "triggerType", type);
413	
414	        AddCommandParameter(cmd, "triggerStartTime", GetDbDateTimeValue(trigger.StartTimeUtc));
415	        AddCommandParameter(cmd, "triggerEndTime", GetDbDateTimeValue(trigger.EndTimeUtc));
416	        AddCommandParameter(cmd, "triggerCalendarName", trigger.CalendarName);
417	        AddCommandParameter(cmd, "triggerMisfireInstruction", trigger.MisfireInstruction);
418	        AddCommandParameter(cmd, "triggerPriority", trigger.Priority);
419	
420	        const string JobDataMapParameter = "triggerJobJobDataMap";
421	        if (updateJobData)
422	        {
423	            AddCommandParameter(cmd, JobDataMapParameter, jobData, DbProvider.Metadata.DbBinaryType);
424	            AddCommandParameter(cmd, "triggerName", trigger.Key.Name);
425	            AddCommandParameter(cmd, "triggerGroup", trigger.Key.Group);
426	        }
427	        else
428	        {
429	            AddCommandParameter(cmd, "triggerName", trigger.Key.Name);
430	            AddCommandParameter(cmd, "triggerGroup", trigger.Key.Group);
431	        }
432	
433	        var updateResult = await cmd.ExecuteNonQueryAsync(cancellationToken).ConfigureAwait(false);
434	
435	        if (type == existingType)
436	        {
437	            if (tDel is null)
438	            {
439	                await UpdateBlobTrigger(conn, trigger, cancellationToken).ConfigureAwait(false);
440	            }
441	            else
442	            {
443	                await tDel.UpdateExtendedTriggerProperties(conn, trigger, state, jobDetail, cancellationToken).ConfigureAwait(false);
444	            }
445	        }
446	        else
447	        {
448	            var existingDel = FindTriggerPersistenceDelegate(existingType);
449	
450	            if (existingDel is null)
451	            {
452	                await DeleteBlobTrigger(conn, trigger.Key, cancellationToken).ConfigureAwait(false);
453	            }
454	            else
455	            {
456	                await existingDel.DeleteExtendedTriggerProperties(conn, trigger.Key, cancellationToken).ConfigureAwait(false);
457	            }
458	
459	            if (tDel is null)
460	            {
461	                await InsertBlobTrigger(conn, trigger, cancellationToken).ConfigureAwait(false);
462	            }
463	            else
464	            {
465	                await tDel.InsertExtendedTriggerProperties(conn, trigger, state, jobDetail, cancellationToken).ConfigureAwait(false);
466	            }
467	        }
468	
469	        return updateResult;
470	    }
