684	    /// <inheritdoc />
685	    public virtual async ValueTask<IOperableTrigger?> SelectTrigger(
686	        ConnectionAndTransactionHolder conn,
687	        TriggerKey triggerKey,
688	        CancellationToken cancellationToken = default)
689	    {
690	        string jobName;
691	        string jobGroup;
692	        string? description;
693	        string triggerType;
694	        string? calendarName;
695	        int misFireInstr;
696	        int priority;
697	
698	        IDictionary? map;
699	
700	        DateTimeOffset? nextFireTimeUtc;
701	        DateTimeOffset? previousFireTimeUtc;
702	        DateTimeOffset startTimeUtc;
703	        DateTimeOffset? endTimeUtc;
704	        DateTimeOffset? misfireOrigFireTime;
705	
706	        ITriggerPersistenceDelegate? tDel = null;
707	        TriggerPropertyBundle? triggerProps = null;
708	
709	        using (var cmd = PrepareCommand(conn, ReplaceTablePrefix(SqlSelectTrigger)))
710	        {
711	            AddCommandParameter(cmd, "schedulerName", schedName);
712	            AddCommandParameter(cmd, "triggerName", triggerKey.Name);
713	            AddCommandParameter(cmd, "triggerGroup", triggerKey.Group);
714	
715	            using (var rs = await cmd.ExecuteReaderAsync(cancellationToken).ConfigureAwait(false))
716	            {
717	                if (!await rs.ReadAsync(cancellationToken).ConfigureAwait(false))
718	                {
719	                    return null;
720	                }
721	
722	                jobName = rs.GetString(ColumnJobName)!;
723	                jobGroup = rs.GetString(ColumnJobGroup)!;
724	                description = rs.GetString(ColumnDescription);
725	                triggerType = rs.GetString(ColumnTriggerType)!;
726	                calendarName = rs.GetString(ColumnCalendarName);
727	                misFireInstr = rs.GetInt32(ColumnMifireInstruction);
728	                priority = rs.GetInt32(ColumnPriority);
729	
730	                map = await ReadMapFromReader(rs, 11).ConfigureAwait(false);
731	
732	                nextFireTimeUtc = GetDateTimeFromDbValue(rs[ColumnNextFireTime]);
733	                previousFireTimeUtc = GetDateTimeFromDbValue(rs[ColumnPreviousFireTime]);
734	                startTimeUtc = GetDateTimeFromDbValue(rs[ColumnStartTime]) ?? DateTimeOffset.MinValue;
735	                endTimeUtc = GetDateTimeFromDbValue(rs[ColumnEndTime]);
736	
737	                // check if we access fast path
738	                if (triggerType is TriggerTypeCron or TriggerTypeSimple)
739	                {
740	                    tDel = FindTriggerPersistenceDelegate(triggerType);
741	                    triggerProps = tDel!.ReadTriggerPropertyBundle(rs);
742	                }
743	
744	                misfireOrigFireTime = GetDateTimeFromDbValue(rs[ColumnMisfireOriginalFireTime]);
745	            }
746	        }
747	
748	        IOperableTrigger? trigger = null;
749	        if (triggerType == TriggerTypeBlob)
750	        {
751	            using var cmd2 = PrepareCommand(conn, ReplaceTablePrefix(SqlSelectBlobTrigger));
752	            AddCommandParameter(cmd2, "schedulerName", schedName);
753	            AddCommandParameter(cmd2, "triggerName", triggerKey.Name);
754	            AddCommandParameter(cmd2, "triggerGroup", triggerKey.Group);
755	            using var rs2 = await cmd2.ExecuteReaderAsync(System.Data.CommandBehavior.SequentialAccess, cancellationToken).ConfigureAwait(false);
756	            if (await rs2.ReadAsync(cancellationToken).ConfigureAwait(false))
757	            {
758	                trigger = await GetObjectFromBlob<IOperableTrigger>(rs2, 0, cancellationToken).ConfigureAwait(false);
759	            }
760	        }
761	        else
762	        {
763	            if (triggerProps is null)
764	            {
765	                // fast path didn't succeed
766	                tDel ??= FindTriggerPersistenceDelegate(triggerType);
767	
768	                if (tDel is null)
769	                {
770	                    Throw.JobPersistenceException("No TriggerPersistenceDelegate for trigger discriminator type: " + triggerType);
771	                }
772	
773	                try
774	                {
775	                    triggerProps = await tDel.LoadExtendedTriggerProperties(conn, triggerKey, cancellationToken).ConfigureAwait(false);
776	                }
777	                catch (InvalidOperationException)
778	                {
779	                    if (await IsTriggerStillPresent(conn, triggerKey, cancellationToken).ConfigureAwait(false))
780	                    {
781	                        throw;
782	                    }
783	
784	                    // QTZ-386 Trigger has been deleted
785	                    return null;
786	                }
787	            }
788	
789	            TriggerBuilder tb = TriggerBuilder.Create()
790	                .WithDescription(description)
791	                .WithPriority(priority)
792	                .StartAt(startTimeUtc)
793	                .EndAt(endTimeUtc)
794	                .WithIdentity(triggerKey)
795	                .ModifiedByCalendar(calendarName)
796	                .WithSchedule(triggerProps.ScheduleBuilder)
797	                .ForJob(new JobKey(jobName, jobGroup));
798	
799	            if (map is not null)
800	            {
801	                bool clearDirtyFlag = !map.Contains(SchedulerConstants.ForceJobDataMapDirty);
802	                tb.UsingJobData(new JobDataMap(map));
803	                if (clearDirtyFlag)
804	                {
805	                    tb.ClearDirty();
806	                }
807	            }
808	
809	            trigger = (IOperableTrigger) tb.Build();
810	
811	            trigger.MisfireInstruction = misFireInstr;
812	            trigger.SetNextFireTimeUtc(nextFireTimeUtc);
813	            trigger.SetPreviousFireTimeUtc(previousFireTimeUtc);
814	
815	            if (misfireOrigFireTime.HasValue && trigger is AbstractTrigger at)
816	            {
817	                at.MisfiredFromFireTimeUtc = misfireOrigFireTime;
818	            }
819	
820	            SetTriggerStateProperties(trigger, triggerProps);
821	        }
822	
823	        return trigger;
824	    }
