1109	    /// <inheritdoc />
1110	    public virtual async ValueTask<List<TriggerAcquireResult>> SelectTriggerToAcquire(
1111	        ConnectionAndTransactionHolder conn,
1112	        DateTimeOffset noLaterThan,
1113	        DateTimeOffset noEarlierThan,
1114	        int maxCount,
1115	        CancellationToken cancellationToken = default)
1116	    {
1117	        if (maxCount < 1)
1118	        {
1119	            maxCount = 1; // we want at least one trigger back.
1120	        }
1121	
1122	        using var cmd = PrepareCommand(conn, ReplaceTablePrefix(GetSelectNextTriggerToAcquireSql(maxCount)));
1123	        List<TriggerAcquireResult> nextTriggers = new();
1124	
1125	        AddCommandParameter(cmd, "schedulerName", schedName);
1126	        AddCommandParameter(cmd, "state", StateWaiting);
1127	        AddCommandParameter(cmd, "noLaterThan", GetDbDateTimeValue(noLaterThan));
1128	        AddCommandParameter(cmd, "noEarlierThan", GetDbDateTimeValue(noEarlierThan));
1129	
1130	        using var rs = await cmd.ExecuteReaderAsync(cancellationToken).ConfigureAwait(false);
1131	        // signal cancel, otherwise ADO.NET might have trouble handling partial reads from open reader
1132	        var shouldStop = false;
1133	        while (await rs.ReadAsync(cancellationToken).ConfigureAwait(false))
1134	        {
1135	            if (shouldStop)
1136	            {
1137	                cmd.Cancel();
1138	                break;
1139	            }
1140	
1141	            if (nextTriggers.Count < maxCount)
1142	            {
1143	                var result = new TriggerAcquireResult(
1144	                    (string) rs[ColumnTriggerName],
1145	                    (string) rs[ColumnTriggerGroup],
1146	                    (string) rs[ColumnJobClass]);
1147	                nextTriggers.Add(result);
1148	            }
1149	            else
1150	            {
1151	                shouldStop = true;
1152	            }
1153	        }
1154	
1155	        return nextTriggers;
1156	    }
