1	using System.Text.Json;
2	using System.Text.Json.Serialization;
3	
4	using Quartz.Impl.Triggers;
5	using Quartz.Serialization.Json.Triggers;
6	using Quartz.Spi;
7	using Quartz.Util;
8	
9	namespace Quartz.Serialization.Json.Converters;
10	
11	internal sealed class TriggerConverter : JsonConverter<ITrigger>
12	{
13	    private static readonly Dictionary<string, ITriggerSerializer> converters = new(StringComparer.OrdinalIgnoreCase);
14	
15	    static TriggerConverter()
16	    {
17	        AddTriggerSerializer<CalendarIntervalTriggerImpl>(new CalendarIntervalTriggerSerializer());
18	        AddTriggerSerializer<CronTriggerImpl>(new CronTriggerSerializer());
19	        AddTriggerSerializer<DailyTimeIntervalTriggerImpl>(new DailyTimeIntervalTriggerSerializer());
20	        AddTriggerSerializer<SimpleTriggerImpl>(new SimpleTriggerSerializer());
21	    }
22	
23	    public override bool CanConvert(Type typeToConvert) => typeof(ITrigger).IsAssignableFrom(typeToConvert);
24	
25	    public override ITrigger Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
26	    {
27	        try
28	        {
29	            var rootElement = JsonDocument.ParseValue(ref reader).RootElement;
30	            var type = rootElement.GetProperty(options.GetPropertyName("TriggerType")).GetString();
31	
32	            var triggerSerializer = GetTriggerSerializer(type);
33	            var scheduleBuilder = triggerSerializer.CreateScheduleBuilder(rootElement, options);
34	
35	            var key = rootElement.GetProperty(options.GetPropertyName("Key")).GetTriggerKey(options);
36	            var jobKey = rootElement.GetProperty(options.GetPropertyName("JobKey")).GetJobKey(options);
37	            var description = rootElement.GetProperty(options.GetPropertyName("Description")).GetString();
38	            var calendarName = rootElement.GetProperty(options.GetPropertyName("CalendarName")).GetString();
39	            var jobDataMap = rootElement.GetProperty(options.GetPropertyName("JobDataMap")).GetJobDataMap(options);
40	            var misfireInstruction = rootElement.GetProperty(options.GetPropertyName("MisfireInstruction")).GetInt32();
41	            var endTimeUtc = rootElement.GetProperty(options.GetPropertyName("EndTimeUtc")).GetDateTimeOffsetOrNull();
42	            var startTimeUtc = rootElement.GetProperty(options.GetPropertyName("StartTimeUtc")).GetDateTimeOffset();
43	            var priority = rootElement.GetProperty(options.GetPropertyName("Priority")).GetInt32();
44	
45	            var builder = TriggerBuilder.Create()
46	                .WithSchedule(scheduleBuilder)
47	                .WithIdentity(key);
48	
49	            if (jobKey is not null)
50	            {
51	                builder = builder.ForJob(jobKey);
52	            }
53	
54	            var trigger = builder
55	                .WithDescription(description)
56	                .ModifiedByCalendar(calendarName)
57	                .UsingJobData(jobDataMap)
58	                .EndAt(endTimeUtc)
59	                .StartAt(startTimeUtc)
60	                .WithPriority(priority)
61	                .Build();
62	
63	            if (trigger is IMutableTrigger mutableTrigger)
64	            {
65	                mutableTrigger.MisfireInstruction = misfireInstruction;
66	            }
67	
68	            if (trigger is IOperableTrigger operableTrigger)
69	            {
70	                // These properties might not exist in the JSON if trigger was serialized with older version
71	                var nextFireTimeUtc = rootElement.GetPropertyOrNull(options.GetPropertyName("NextFireTimeUtc"))?.GetDateTimeOffsetOrNull();
72	                var previousFireTimeUtc = rootElement.GetPropertyOrNull(options.GetPropertyName("PreviousFireTimeUtc"))?.GetDateTimeOffsetOrNull();
73	
74	                operableTrigger.SetNextFireTimeUtc(nextFireTimeUtc);
75	                operableTrigger.SetPreviousFireTimeUtc(previousFireTimeUtc);
76	            }
77	
78	            triggerSerializer.DeserializeFields(trigger, rootElement, options);
79	            return trigger;
80	        }
81	        catch (Exception e)
82	        {
83	            throw new JsonSerializationException("Failed to parse ITrigger from json", e);
84	        }
85	    }
86	
87	    public override void Write(Utf8JsonWriter writer, ITrigger value, JsonSerializerOptions options)
88	    {
89	        try
90	        {
91	            writer.WriteStartObject();
92	            var type = value.GetType().AssemblyQualifiedNameWithoutVersion();
93	            var triggerSerializer = GetTriggerSerializer(type);
94	
95	            writer.WriteString(options.GetPropertyName("TriggerType"), triggerSerializer.TriggerTypeForJson);
96	
97	            writer.WriteKey(options.GetPropertyName("Key"), value.Key, options);
98	            writer.WriteKey(options.GetPropertyName("JobKey"), value.JobKey, options);
99	            writer.WriteString(options.GetPropertyName("Description"), value.Description);
100	            writer.WriteString(options.GetPropertyName("CalendarName"), value.CalendarName);
101	            writer.WritePropertyName(options.GetPropertyName("JobDataMap"));
102	            writer.WriteJobDataMapValue(value.JobDataMap, options);
103	            writer.WriteNumber(options.GetPropertyName("MisfireInstruction"), value.MisfireInstruction);
104	            writer.WriteString(options.GetPropertyName("StartTimeUtc"), value.StartTimeUtc);
105	            writer.WriteString(options.GetPropertyName("EndTimeUtc"), value.EndTimeUtc);
